// ===== Rating remap =====
// Recompute each cruise.rating from its priceFrom so that cheaper boats sit
// around 4.5 ★ and the most expensive boats reach 4.9 ★ (Standard floor 4.5,
// max 4.9 — never above). Done once at module load; original .reviews preserved.
(() => {
  if (!CRUISES.length) return;
  const prices = CRUISES.map((c) => c.priceFrom).filter((p) => typeof p === "number" && p > 0);
  if (!prices.length) return;
  // Use a robust range: 10th–90th percentile to absorb extreme outliers.
  const sorted = [...prices].sort((a, b) => a - b);
  const p10 = sorted[Math.floor(sorted.length * 0.1)] ?? sorted[0];
  const p90 = sorted[Math.floor(sorted.length * 0.9)] ?? sorted[sorted.length - 1];
  const span = Math.max(1, p90 - p10);
  for (const c of CRUISES) {
    const clamped = Math.max(p10, Math.min(p90, c.priceFrom));
    const t = (clamped - p10) / span; // 0 → 1
    // Map 0..1 to 4.5..4.9 and round to one decimal
    const r = 4.5 + t * 0.4;
    c.rating = Math.round(r * 10) / 10;
  }
})();

